<template>
  <div style="margin: 0 20px 20px;">
    <a-menu v-model="current" mode="horizontal" :style="{ display: 'flex' }" @click="change">
      <a-menu-item key="unratedContestants" :style="{ flex: '1', textAlign: 'center' }">未打分（{{ list['unratedContestants'].length }}）</a-menu-item>
      <a-menu-item key="ratedContestants" :style="{ flex: '1', textAlign: 'center' }">已打分（{{ list['ratedContestants'].length }}）</a-menu-item>
    </a-menu>
    <a-list item-layout="horizontal" :data-source="list[current[0]]" v-if="(!loading1) && (!loading2)">
      <a-list-item slot="renderItem" slot-scope="item">
        <a-list-item-meta description="">
          <div slot="title">
            <div class="parent-div">
              <div style="display: flex;">
                <div style="width: 48px; flex-shrink: 0;">
                  <a-icon type="check-square" style="font-size: 48px; color: brown;"/>
                </div>
                <div style="flex-grow: 1; padding-left: 20px;">
                  <h3 style="margin-bottom: 2px; font-weight: 700;">{{ current[0] === 'unratedContestants' ? item.name : item.contestantName }}</h3>
                  <p style="margin-bottom: 0; font-size: 16px; color: #888">{{ item.description }}</p>
                  <span v-if="current[0] === 'unratedContestants'" style="color: blue; font-size: 20px; float: right;" @click="scoreEdit(item.id)">评分</span>
                  <span v-else style="font-size: 20px; float: right;">
                    {{ item.totalScore }}分 <a @click="$router.push({ name: 'judgeContestantDetail', params: { voteId: $route.query.voteId, cid: item.contestantId } })">详情></a>
                  </span>
                </div>
              </div>
            </div>
          </div>
        </a-list-item-meta>
      </a-list-item>
    </a-list>
    <div style="height:30px; text-align: center; background-color: #fff; border-radius: 4px; margin-bottom: 20px; padding: 30px 50px; margin: 20px 0;" v-else>
      <a-spin />
    </div>
  </div>
</template>
<script>
import { getUatedContestants, getRatedContestants } from '@/api/judge'
export default {
  data() {
    return {
      current: ['unratedContestants'],
      list: {
        unratedContestants: [],
        ratedContestants: [],
      },
      loading1: false,
      loading2: false,
    }
  },
  mounted() {
    this.loadData(true)
  },
  methods: {
    loadData(bool) {
      this.loading1 = true
      this.loading2 = true
      getUatedContestants(this.$route.query.voteId).then(res => {
        this.list['unratedContestants'] = res
        if (res.length === 0 && bool) {
          this.current = ['ratedContestants']
        }
      }).finally(() => { this.loading1 = false })
      getRatedContestants(this.$route.query.voteId).then(res => {
        this.list['ratedContestants'] = res
      }).finally(() => { this.loading2 = false })
    },
    change() {
      this.loadData(false)
    },
    scoreEdit(cid) {
      this.$router.push({
        name: 'judgeScoreEdit',
        query: {
          cid: cid,
          voteId: this.$route.query.voteId,
        },
      })
    },
  },
}
</script>
